import asyncio
import websockets
import json
import uuid
import logging

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class Item:
    def __init__(self, item_id, name, owner_id=None):
        self.item_id = item_id
        self.name = name
        self.owner_id = owner_id

    def to_dict(self):
        return {"item_id": self.item_id, "name": self.name, "owner_id": self.owner_id}

class Player:
    def __init__(self, player_id, name):
        self.player_id = player_id
        self.name = name
        self.inventory = {}  # item_id -> Item object
        self.websocket = None # Store the websocket connection for sending messages

    def add_item(self, item):
        if item.item_id in self.inventory:
            logging.warning(f"Player {self.player_id} already has item {item.item_id}")
            return False
        self.inventory[item.item_id] = item
        item.owner_id = self.player_id
        return True

    def remove_item(self, item_id):
        if item_id not in self.inventory:
            logging.warning(f"Player {self.player_id} does not have item {item_id}")
            return None
        item = self.inventory.pop(item_id)
        item.owner_id = None
        return item

    def get_inventory_list(self):
        return [item.to_dict() for item in self.inventory.values()]

    def to_dict(self):
        return {
            "player_id": self.player_id,
            "name": self.name,
            "inventory": self.get_inventory_list()
        }

class GameServer:
    def __init__(self):
        self.players = {}  # player_id -> Player object
        self.items = {}    # item_id -> Item object (global item registry)
        self.connected_websockets = {} # player_id -> websocket
        self.trade_locks = asyncio.Lock() # Global lock for trade operations

        # Initial data for demonstration
        self._initialize_game_data()

    def _initialize_game_data(self):
        # Create some initial players
        player1 = Player("player1", "Alice")
        player2 = Player("player2", "Bob")
        player3 = Player("player3", "Charlie")
        self.players[player1.player_id] = player1
        self.players[player2.player_id] = player2
        self.players[player3.player_id] = player3

        # Create some initial items
        item1 = Item(str(uuid.uuid4()), "Sword of Destiny")
        item2 = Item(str(uuid.uuid4()), "Shield of Valor")
        item3 = Item(str(uuid.uuid4()), "Potion of Healing")
        item4 = Item(str(uuid.uuid4()), "Ring of Power")
        item5 = Item(str(uuid.uuid4()), "Amulet of Wisdom")

        self.items[item1.item_id] = item1
        self.items[item2.item_id] = item2
        self.items[item3.item_id] = item3
        self.items[item4.item_id] = item4
        self.items[item5.item_id] = item5

        # Distribute items
        player1.add_item(item1)
        player1.add_item(item2)
        player2.add_item(item3)
        player3.add_item(item4)
        player3.add_item(item5)

        logging.info("Game data initialized.")
        logging.info(f"Player1 inventory: {[item.name for item in player1.inventory.values()]}")
        logging.info(f"Player2 inventory: {[item.name for item in player2.inventory.values()]}")
        logging.info(f"Player3 inventory: {[item.name for item in player3.inventory.values()]}")


    async def _send_message(self, player_id, message_type, payload):
        if player_id in self.connected_websockets:
            websocket = self.connected_websockets[player_id]
            try:
                await websocket.send(json.dumps({"type": message_type, "payload": payload}))
                logging.info(f"Sent {message_type} to {player_id}")
            except websockets.exceptions.ConnectionClosed:
                logging.warning(f"Failed to send message to {player_id}: Connection closed.")
                del self.connected_websockets[player_id]
        else:
            logging.warning(f"Player {player_id} not connected, cannot send message.")

    async def _broadcast_inventory_update(self, player_id):
        player = self.players.get(player_id)
        if player:
            await self._send_message(player_id, "INVENTORY_UPDATE", player.get_inventory_list())

    async def _broadcast_player_update(self, player_id):
        player = self.players.get(player_id)
        if player:
            await self._send_message(player_id, "PLAYER_UPDATE", player.to_dict())

    async def _handle_login(self, websocket, player_id):
        if player_id not in self.players:
            logging.warning(f"Login attempt for unknown player: {player_id}")
            await websocket.send(json.dumps({"type": "ERROR", "payload": "Player not found."}))
            return None

        if player_id in self.connected_websockets:
            logging.warning(f"Player {player_id} already connected. Kicking old connection.")
            # Optionally kick the old connection
            old_ws = self.connected_websockets[player_id]
            try:
                await old_ws.close(code=1008, reason="New connection established.")
            except Exception as e:
                logging.error(f"Error closing old connection for {player_id}: {e}")

        self.connected_websockets[player_id] = websocket
        self.players[player_id].websocket = websocket # Update player object with current websocket
        logging.info(f"Player {player_id} logged in.")
        await self._send_message(player_id, "LOGIN_SUCCESS", self.players[player_id].to_dict())
        return self.players[player_id]

    async def _handle_get_inventory(self, player):
        await self._broadcast_inventory_update(player.player_id)

    async def _handle_trade_item(self, sender_player, receiver_player_id, item_id):
        async with self.trade_locks: # Ensure only one trade operation at a time
            logging.info(f"Attempting trade: {sender_player.player_id} -> {receiver_player_id} item {item_id}")

            if receiver_player_id not in self.players:
                await self._send_message(sender_player.player_id, "ERROR", "Receiver player not found.")
                return

            receiver_player = self.players[receiver_player_id]

            if item_id not in sender_player.inventory:
                await self._send_message(sender_player.player_id, "ERROR", f"You do not own item {item_id}.")
                return

            item_to_trade = sender_player.remove_item(item_id)
            if item_to_trade:
                receiver_player.add_item(item_to_trade)
                logging.info(f"Trade successful: {sender_player.player_id} gave {item_to_trade.name} to {receiver_player_id}")

                await self._send_message(sender_player.player_id, "TRADE_SUCCESS", {
                    "item_id": item_id,
                    "from": sender_player.player_id,
                    "to": receiver_player_id,
                    "message": f"You gave {item_to_trade.name} to {receiver_player.name}."
                })
                await self._send_message(receiver_player_id, "TRADE_SUCCESS", {
                    "item_id": item_id,
                    "from": sender_player.player_id,
                    "to": receiver_player_id,
                    "message": f"You received {item_to_trade.name} from {sender_player.name}."
                })

                # Update inventories for both players
                await self._broadcast_inventory_update(sender_player.player_id)
                await self._broadcast_inventory_update(receiver_player_id)
            else:
                await self._send_message(sender_player.player_id, "ERROR", f"Failed to remove item {item_id} from your inventory.")


    async def handler(self, websocket, path):
        current_player = None
        try:
            async for message in websocket:
                data = json.loads(message)
                message_type = data.get("type")
                payload = data.get("payload")
                logging.info(f"Received message: {message_type} from {current_player.player_id if current_player else 'unauthenticated'}")

                if message_type == "LOGIN":
                    player_id = payload.get("player_id")
                    current_player = await self._handle_login(websocket, player_id)
                    if not current_player:
                        break # Close connection if login failed
                elif not current_player:
                    logging.warning("Received message before login. Closing connection.")
                    await websocket.send(json.dumps({"type": "ERROR", "payload": "Please login first."}))
                    break # Close connection if not logged in
                elif message_type == "GET_INVENTORY":
                    await self._handle_get_inventory(current_player)
                elif message_type == "TRADE_ITEM":
                    receiver_player_id = payload.get("receiver_player_id")
                    item_id = payload.get("item_id")
                    if receiver_player_id and item_id:
                        await self._handle_trade_item(current_player, receiver_player_id, item_id)
                    else:
                        await self._send_message(current_player.player_id, "ERROR", "Invalid TRADE_ITEM payload.")
                elif message_type == "GET_ALL_PLAYERS":
                    all_players_data = [p.to_dict() for p in self.players.values()]
                    await self._send_message(current_player.player_id, "ALL_PLAYERS", all_players_data)
                else:
                    await self._send_message(current_player.player_id, "ERROR", "Unknown message type.")

        except websockets.exceptions.ConnectionClosedOK:
            logging.info(f"Connection closed normally for {current_player.player_id if current_player else 'unauthenticated'}")
        except websockets.exceptions.ConnectionClosedError as e:
            logging.error(f"Connection closed with error for {current_player.player_id if current_player else 'unauthenticated'}: {e}")
        except Exception as e:
            logging.error(f"An unexpected error occurred for {current_player.player_id if current_player else 'unauthenticated'}: {e}", exc_info=True)
        finally:
            if current_player and current_player.player_id in self.connected_websockets:
                logging.info(f"Player {current_player.player_id} disconnected.")
                del self.connected_websockets[current_player.player_id]
                current_player.websocket = None # Clear the websocket reference

async def main():
    server = GameServer()
    async with websockets.serve(server.handler, "localhost", 8765):
        logging.info("Game server started on ws://localhost:8765")
        await asyncio.Future()  # Run forever

if __name__ == "__main__":
    asyncio.run(main())